import { _ as _export_sfc } from "./plugin-vue_export-helper.1tPrXgE0.js";
const __pageData = JSON.parse('{"title":"Roadmap","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md","lastUpdated":1776952772000}');
